import { readFileSync } from 'node:fs';
const footer = readFileSync('apps/liora/src/tui/components/chrome/footer.ts','utf8');
const status = readFileSync('apps/liora/src/tui/components/messages/status-panel.ts','utf8');
const idx = JSON.parse(readFileSync('packages/agent-core/src/skill/catalog-search-index.json','utf8'));
const names = new Set((idx.skills||[]).map(s=>String(s.name||'').toLowerCase()));
const fails=[];
if (!footer.includes('formatOfficeFooterBadge')) fails.push('footer-fn');
if (!footer.includes("label: 'office'")) fails.push('office-label');
if (!footer.includes('formatWebFooterBadge')) fails.push('web-badge');
if (!status.includes('docx / pptx / xlsx')) fails.push('status-office');
for (const n of ['docx','pptx','xlsx']) if (!names.has(n)) fails.push('catalog-'+n);
if (fails.length) { console.error(fails.join(',')); process.exit(1);} console.log('office-zero-config-source-ok');
